document.addEventListener('DOMContentLoaded', () => {const initPhotoCarousels = () => {document.querySelectorAll('.photo-carousel').forEach((carousel) => {const viewport = carousel.querySelector('.photo-carousel-viewport');const prev = carousel.querySelector('.photo-carousel-prev');const next = carousel.querySelector('.photo-carousel-next');if (!viewport) return;const getStep = () => {const slide = viewport.querySelector('.photo-carousel-slide');if (!slide) return viewport.clientWidth;const track = viewport.querySelector('.photo-carousel-track');const gap = track ? parseFloat(getComputedStyle(track).gap) || 16 : 16;return slide.getBoundingClientRect().width + gap;};const updateButtons = () => {const maxScroll = viewport.scrollWidth - viewport.clientWidth;const canScroll = maxScroll > 4;carousel.classList.toggle('photo-carousel--static', !canScroll);if (!canScroll) return;prev?.toggleAttribute('disabled', viewport.scrollLeft <= 4);next?.toggleAttribute('disabled', viewport.scrollLeft >= maxScroll - 4);};const scrollByStep = (direction) => {viewport.scrollBy({ left: direction * getStep(), behavior: 'smooth' });};prev?.addEventListener('click', () => scrollByStep(-1));next?.addEventListener('click', () => scrollByStep(1));viewport.addEventListener('scroll', updateButtons, { passive: true });window.addEventListener('resize', updateButtons);carousel.querySelectorAll('img').forEach((img) => {if (!img.complete) {img.addEventListener('load', updateButtons, { once: true });}});if (typeof ResizeObserver !== 'undefined') {const ro = new ResizeObserver(updateButtons);ro.observe(viewport);}updateButtons();});};const initSite = () => {AOS.init({ duration: 800, once: true, offset: 80 });GLightbox({selector: '.glightbox',touchNavigation: true,loop: true,openEffect: 'zoom',closeEffect: 'fade',});initPhotoCarousels();};if (document.getElementById('mainSite')?.classList.contains('is-visible')) {initSite();} else {window.addEventListener('siteReady', initSite, { once: true });}const navbar = document.getElementById('mainNav');const siteNavOffcanvas = document.getElementById('siteNavOffcanvas');if (siteNavOffcanvas && typeof bootstrap !== 'undefined') {const offcanvas = bootstrap.Offcanvas.getOrCreateInstance(siteNavOffcanvas);siteNavOffcanvas.querySelectorAll('.nav-link').forEach((link) => {link.addEventListener('click', () => {if (siteNavOffcanvas.classList.contains('show')) {offcanvas.hide();}});});}const scrollToTopBtn = document.getElementById('scrollToTop');const handleScroll = () => {if (window.scrollY > 60) {navbar?.classList.add('scrolled');} else {navbar?.classList.remove('scrolled');}if (scrollToTopBtn) {scrollToTopBtn.classList.toggle('is-visible', window.scrollY > 400);}};window.addEventListener('scroll', handleScroll);handleScroll();scrollToTopBtn?.addEventListener('click', () => {window.scrollTo({ top: 0, behavior: 'smooth' });});document.querySelectorAll('a[href^="#"]').forEach(link => {link.addEventListener('click', (e) => {const target = document.querySelector(link.getAttribute('href'));if (target) {e.preventDefault();target.scrollIntoView({ behavior: 'smooth', block: 'start' });}});});const showAlert = (el, message, type = 'success') => {el.textContent = message;el.className = `alert mt-4 alert-${type}`;el.classList.remove('d-none');setTimeout(() => el.classList.add('d-none'), 6000);};const confirmForm = document.getElementById('rsvpConfirmForm');confirmForm?.addEventListener('submit', async (e) => {e.preventDefault();const alert = document.getElementById('rsvpAlert');const data = Object.fromEntries(new FormData(confirmForm));try {const res = await fetch('/api/rsvp/confirm', {method: 'POST',headers: { 'Content-Type': 'application/json' },body: JSON.stringify(data),});const json = await res.json();if (json.success) {showAlert(alert, json.message, 'success');confirmForm.reset();} else {showAlert(alert, json.message || 'Une erreur est survenue.', 'danger');}} catch {showAlert(alert, 'Erreur de connexion. Veuillez réessayer.', 'danger');}});const declineForm = document.getElementById('rsvpDeclineForm');declineForm?.addEventListener('submit', async (e) => {e.preventDefault();const alert = document.getElementById('rsvpAlert');const data = Object.fromEntries(new FormData(declineForm));try {const res = await fetch('/api/rsvp/decline', {method: 'POST',headers: { 'Content-Type': 'application/json' },body: JSON.stringify(data),});const json = await res.json();if (json.success) {showAlert(alert, json.message, 'success');declineForm.reset();} else {showAlert(alert, json.message || 'Une erreur est survenue.', 'danger');}} catch {showAlert(alert, 'Erreur de connexion. Veuillez réessayer.', 'danger');}});const guestbookForm = document.getElementById('guestbookForm');guestbookForm?.addEventListener('submit', async (e) => {e.preventDefault();const alert = document.getElementById('guestbookAlert');const data = Object.fromEntries(new FormData(guestbookForm));try {const res = await fetch('/api/guestbook', {method: 'POST',headers: { 'Content-Type': 'application/json' },body: JSON.stringify(data),});const json = await res.json();if (json.success) {alert.textContent = json.message;alert.className = 'alert mt-3 alert-success';alert.classList.remove('d-none');if (typeof window.addGuestbookFloatCard === 'function') {window.addGuestbookFloatCard(data);}guestbookForm.reset();} else {alert.textContent = json.message || 'Une erreur est survenue.';alert.className = 'alert mt-3 alert-danger';alert.classList.remove('d-none');}} catch {alert.textContent = 'Erreur de connexion.';alert.className = 'alert mt-3 alert-danger';alert.classList.remove('d-none');}});document.querySelectorAll('.share-btn').forEach(btn => {btn.addEventListener('click', () => {const raw = btn.dataset.url || '';const url = raw.startsWith('http') ? raw : window.location.origin + raw;if (navigator.share) {navigator.share({ title: 'Notre Mariage', url });} else {navigator.clipboard.writeText(url);btn.innerHTML = '<i class="bi bi-check"></i>';setTimeout(() => { btn.innerHTML = '<i class="bi bi-share"></i>'; }, 2000);}});});const countdownEl = document.getElementById('countdown');if (countdownEl) {const weddingDate = new Date(countdownEl.dataset.wedding);const daysEl = document.getElementById('cdDays');const hoursEl = document.getElementById('cdHours');const minutesEl = document.getElementById('cdMinutes');const secondsEl = document.getElementById('cdSeconds');const pad = (n) => String(n).padStart(2, '0');const tick = () => {const diff = weddingDate - new Date();if (diff <= 0) {countdownEl.classList.add('is-past');const label = countdownEl.querySelector('.countdown-label');const pastMessage = countdownEl.dataset.countdownPast || "C'est aujourd'hui — le grand jour est arrivé !";if (label) label.textContent = pastMessage;if (daysEl) daysEl.textContent = '0';if (hoursEl) hoursEl.textContent = '00';if (minutesEl) minutesEl.textContent = '00';if (secondsEl) secondsEl.textContent = '00';return;}if (daysEl) daysEl.textContent = Math.floor(diff / 86400000);if (hoursEl) hoursEl.textContent = pad(Math.floor((diff / 3600000) % 24));if (minutesEl) minutesEl.textContent = pad(Math.floor((diff / 60000) % 60));if (secondsEl) secondsEl.textContent = pad(Math.floor((diff / 1000) % 60));};tick();setInterval(tick, 1000);}});